head.script:
scwin.loUpperLobranCd;
scwin.args;
scwin.cvsslMgntNo;
scwin.impExpClsCd;

scwin.comboRtnFlag00;
scwin.comboRtnFlag01;
scwin.comboRtnFlag02;
scwin.comboRtnFlag03;
scwin.interval00;
scwin.interval01;
scwin.interval02;
scwin.interval03;

scwin.arrParent;
scwin.toDay;
scwin.memJson;

scwin.arrRtnVal;
scwin.gv_bondTransExpireDt;
scwin.gv_strExistTF;
scwin.gv_userClsCd;
scwin.gv_clntNo;
scwin.gv_clntNm;
scwin.gv_strAllSearchTF;

scwin.showGridNm;

scwin.udc_objNm;

scwin.rd_lobranCond_val;

scwin.onpageload = async function() {
    //전역변수값 셋팅함수.
	scwin.initSetVal();


    const codeOptions01 = [
        { grpCd: "ZZ307", compID: "lc_wrkDstClsCd" },  //계통콤보에 공통코드셋팅처리. 
        { grpCd: "ZZ617", compID: "gr_retrieveUsableVehiclesPresent1:eqDriveWayCd,gr_retrieveUsableVehiclesPresent2:eqDriveWayCd" },  //제조사콤보에 공통코드셋팅처리.
    ];
    $c.data.setCommonCode(codeOptions01, scwin.commonCodeCallBack01);

    scwin.interval00 = setInterval(async function() {
        if(scwin.comboRtnFlag00 == true) {
            clearInterval(scwin.interval00);
            //초기화
  	        await scwin.f_OnLoad();
        }
    }, 100);
};


scwin.initSetVal = function() {
    if(Object.keys($c.data.getParameter()).length > 0) {
        scwin.arrParent = $c.data.getParameter()[Object.keys($c.data.getParameter())[0]];
    }

    var popTitle = $c.data.getParameter().menuInfo.popupName;
    if(popTitle == undefined || popTitle == null || popTitle == "") {
        popTitle = "가용차량 팝업";
        $c.data.getParameter().menuInfo.popupName = popTitle;
    }

    scwin.toDay = new Date(WebSquare.date.getCurrentServerDate().substring(0, 4),WebSquare.date.getCurrentServerDate().substring(4, 6),WebSquare.date.getCurrentServerDate().substring(6, 8));

    scwin.arrRtnVal = new Array();

    scwin.memJson = $c.data.getMemInfo();
    scwin.gv_userClsCd = scwin.memJson.userClsCd;
    scwin.gv_clntNo = scwin.memJson.clntNo;
    scwin.gv_clntNm = scwin.memJson.clntNm;
    scwin.gv_strAllSearchTF = "T";

    scwin.comboRtnFlag00 = false;
    scwin.comboRtnFlag01 = false;
    scwin.comboRtnFlag02 = false;
    scwin.comboRtnFlag03 = false;

    scwin.showGridNm = "gr_retrieveUsableVehiclesPresent1";
};

//udc 컴포넌트 onload 완료시...
scwin.onUdcCompleted = async function() {
    document.body.addEventListener('keydown', scwin.Go_searchPopup);
};

scwin.commonCodeCallBack01 =  function() {

    ds_grd_wrkDstCd.removeAll();

    $p.getComponentById(lc_wrkDstClsCd.getDataListInfo().id).getCellData(i, "cd")

    for(var i=0;i<$p.getComponentById(lc_wrkDstClsCd.getDataListInfo().id).getRowCount();i++) {
        var nRow = ds_grd_wrkDstCd.getRowCount();
        ds_grd_wrkDstCd.insertRow(nRow);
        ds_grd_wrkDstCd.setCellData(nRow, "cd", $p.getComponentById(lc_wrkDstClsCd.getDataListInfo().id).getCellData(i, "cd"));
        ds_grd_wrkDstCd.setCellData(nRow, "cdNm", $p.getComponentById(lc_wrkDstClsCd.getDataListInfo().id).getCellData(i, "cdNm"));
    }

    $p.getComponentById(lc_wrkDstClsCd.getDataListInfo().id).insertRow(0);
    $p.getComponentById(lc_wrkDstClsCd.getDataListInfo().id).setCellData(0,"cd","");
    $p.getComponentById(lc_wrkDstClsCd.getDataListInfo().id).setCellData(0,"cdNm","전체");

    scwin.comboRtnFlag00 = true;
};

scwin.Go_searchPopup = function (e) {
    if ( $p.getComponentById(e.srcElement.id).org_id == "ed_nameU" && e.keyCode == 8 ) {
        em_clntNo.setValue("");
    }

    if ( $p.getComponentById(e.srcElement.id).org_id == "ed_codeU" && e.keyCode == 8 ) {
        txt_clntNm.setValue("");
    }
};



//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.f_OnLoad = async function() {
    //점소코드콤보
    //submit 처리.
    scwin.comboRtnFlag01 = false;
    let objSubmit = await $c.sbm.execute(sbm_lobran);
    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_lobran_submitdone();
    } else {
        scwin.comboRtnFlag01 = false;
    }

    scwin.interval01 = setInterval(async function() {
        if(scwin.comboRtnFlag01 == true) {
            clearInterval(scwin.interval01);
            //차량종류콤보
            scwin.comboRtnFlag02 = false;
            await scwin.f_vehclKnd();

            scwin.interval02 = setInterval(async function() {
                if(scwin.comboRtnFlag02 == true) {
                    clearInterval(scwin.interval02);

                    //화물구분콤보
                    scwin.comboRtnFlag03 = false;
                    await scwin.f_cargoCls();

                    scwin.interval03 = setInterval(async function() {
                        if(scwin.comboRtnFlag03 == true) {
                            clearInterval(scwin.interval03);
                            await scwin.f_OnLoad_after();
                        }
                    }, 150);
                }
            }, 150);
        }
    }, 150);
};

scwin.sbm_lobran_submitdone = async function (e) {
    //for=ds_lobranCd event=OnLoadCompleted
    ds_lobranCd.insertRow(0);
    ds_lobranCd.setCellData(0,"lobranCd", "");
    ds_lobranCd.setCellData(0,"lobranNm", "전체");

    lc_lobranCd.setValue(scwin.arrParent[0][0]);
    if (scwin.gv_strAllSearchTF == "F") {
        lc_lobranCd.setValue("");
    }

    scwin.comboRtnFlag01 = true;
};

scwin.f_OnLoad_after = async function() {
    /*
    var dsHeader = "lobranCd:STRING(4)"
                    + ",wrkDst:STRING(1)"
                    + ",vehclKnd:STRING(2)"
                    + ",nrm:STRING(2)"
                    + ",coCls:STRING(2)"
                    + ",clntNo:STRING(6)"
                    + ",usblDt:STRING(8)"
                    + ",district:STRING(3)"
                    + ",vehclShortCd:STRING(7)"
                    + ",cargoClsCd:STRING(1)" 
                    + ",schCond:STRING"
                    + ",lobranCond:STRING"
                    ;

    ds_search.SetDataHeader(dsHeader); 
    */
    ds_search.insertRow(0);
    ds_search.setRowPosition(0);

    if (scwin.arrParent[1].length > 0) {
        scwin.gv_bondTransExpireDt 	= scwin.arrParent[1][0];	//보세만료일자
        scwin.gv_strExistTF 			= scwin.arrParent[1][1];
        scwin.gv_strAllSearchTF 		= scwin.arrParent[1][2];
    }

    ds_search.setCellData(0, "lobranCd", scwin.arrParent[0][0]);
    ds_search.setCellData(0, "wrkDst", scwin.arrParent[0][1]);
    ds_search.setCellData(0, "district", scwin.arrParent[0][2]);
    ds_search.setCellData(0, "cargoClsCd", scwin.arrParent[0][3]);
    ds_search.setCellData(0, "usblDt", scwin.arrParent[0][4]);
    ds_search.setCellData(0, "vehclShortCd", scwin.arrParent[0][5]);
    ds_search.setCellData(0, "clntNo", scwin.arrParent[0][6]);
    ds_search.setCellData(0, "schCond", scwin.arrParent[0][8]);
    ds_search.setCellData(0, "vehclKnd", scwin.arrParent[0][9]);
    ds_search.setCellData(0, "lobranCond", "1");

    if (scwin.gv_strAllSearchTF == "F") {
        ds_search.setCellData(0, "lobranCd", "");
        ds_search.setCellData(0, "wrkDst", "");
        ds_search.setCellData(0, "cargoClsCd", "");
        ds_search.setCellData(0, "vehclKnd", "");
    }
    if (scwin.gv_strAllSearchTF == "T" && ds_search.getCellData(0, "lobranCd") == "6BB") {
        ds_search.setCellData(0, "wrkDst", "");
        ds_search.setCellData(0, "cargoClsCd", "");
        ds_search.setCellData(0, "vehclKnd", "");
    }

    if(ds_search.getCellData(0, "vehclShortCd") != ""){
        await scwin.f_Retrieve();
    }

    lc_wrkDstClsCd.setValue(scwin.arrParent[0][1]);		//작업구간
    lc_vehclKnd.setValue(scwin.arrParent[0][9]);			//차량종류
    em_usblDt.setValue(scwin.arrParent[0][4]);
    em_vehclShortCd.setValue(scwin.arrParent[0][5]);
    em_clntNo.setValue(scwin.arrParent[0][6]);
    txt_clntNm.setValue(scwin.arrParent[0][7]);
    rd_lobranCond.setValue("1");

    scwin.rd_lobranCond_val = "1";

    if (scwin.gv_strAllSearchTF == "F") {
        lc_wrkDstClsCd.setValue("");		//작업구간
        lc_vehclKnd.setValue("");		//차량종류
        lc_cargoClsCd.setValue("");
    }
    if (scwin.gv_strAllSearchTF == "T" && ds_search.getCellData(0, "lobranCd") == "6BB") {
        rd_lobranCond.setValue(ds_search.getCellData(0, "lobranCd"));

        scwin.rd_lobranCond_val = ds_search.getCellData(0, "lobranCd");

        lc_wrkDstClsCd.setValue("");		//작업구간
        lc_vehclKnd.setValue("");		//차량종류
        lc_cargoClsCd.setValue("");
    }

    if (scwin.gv_userClsCd == DsConstants.USER_CLS_CD_COP_CO) {
        em_clntNo.setValue(scwin.gv_clntNo);
        txt_clntNm.setValue(scwin.gv_clntNm);
        $c.gus.cfDisableObjects([em_clntNo, txt_clntNm, img_clntNo]);
    } else {
        em_clntNo.focus();
    }
};


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    let ret = await $c.gus.cfValidate([em_usblDt]);
    if (!ret) {
        return; 
    }

	if (scwin.gv_strAllSearchTF == "F") {
		if (em_vehclShortCd.getValue().trim() == "" && (lc_lobranCd.getValue() == "" || lc_cargoClsCd.getValue() == "")) {
			lc_lobranCd.setValue(scwin.arrParent[0][0]);
			lc_cargoClsCd.setValue(scwin.arrParent[0][3]);
		}
		if (em_vehclShortCd.getValue().trim() == "" && (lc_lobranCd.getValue() == "" || lc_cargoClsCd.getValue() == "")) {
			await $c.gus.cfAlertMsg("차량단축번호로 조회한 경우에는 배차점소, 운송화물구분을 지정해야 합니다");
			return;
		}

	}

	if(em_vehclShortCd.getValue() == ""){
		await $c.win.alert("차량단축번호는 1자리 이상 넣으신후 조회하시기 바랍니다");
		em_vehclShortCd.focus();
		return false;
	}

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_retrieve);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_retrieve_submitdone();
    }
};

scwin.sbm_retrieve_submitdone = async function (e) {
    await scwin.retrieveEnd();
};


//-------------------------------------------------------------------------
// 결과값 리턴
//-------------------------------------------------------------------------
scwin.f_rtnValue = async function() {
    let ds_obj;
    if(scwin.showGridNm == "gr_retrieveUsableVehiclesPresent1") {
        ds_obj = ds_results;
    } else if(scwin.showGridNm == "gr_retrieveUsableVehiclesPresent2") {
        ds_obj = ds_results2;
    }

    var v_msg = "";
	var cnt = 0;

	for (var i = 0, cnt = 0; i < ds_obj.getRowCount(); i++) {
		if (ds_obj.getCellData(i, "chk") == "0") {
			continue;
		}

		if (scwin.gv_bondTransExpireDt != "") {
			var v_bondTransStDt  = ds_obj.getCellData(i, "bondTransStDt");	//보세운송 시작일자
			var v_bondTransEndDt = ds_obj.getCellData(i, "bondTransEndDt");	//보세운송 종료일자

			var v_diff = WebSquare.date.dateDiff(scwin.gv_bondTransExpireDt, v_bondTransEndDt);
			if (v_diff <= 15) {
				await $c.gus.cfAlertMsg("보세운송일자 갱신일이 " + v_diff + "일 남았습니다. 참고하십시오");
			}
		}

        let rtn;
		if (ds_obj.getCellData(i, "eqStsCd") == "NA") {
            rtn = await $c.win.confirm("차량번호" + ds_obj.getCellData(i, "vehclNo") + "는 비가용차량입니다.<br>계속하시겠습니까?");
			if (!rtn) {
				ds_obj.undoRow(i);
				return;
			}
		} else if (ds_obj.getCellData(i, "eqStsCd") == DsConstants.EQ_STS_CD_ON) {
			rtn = await $c.win.confirm("차량번호" + ds_obj.getCellData(i, "vehclNo") + "는 사용중인 차량입니다.<br>계속하시겠습니까?");
            if (!rtn) {
				ds_obj.undoRow(i);
				return;
			}
		}
		if (ds_obj.getCellData(i, "wrkIndictYn") != "0") {
			v_msg = "[작업지시번호 : " + ds_obj.getCellData(i, "transWrkIndictNo")
				  + ", 차량번호 : " + ds_obj.getCellData(i, "vehclNo") + "] "
				  + "사용예정중인 차량입니다.<br>계속하시겠습니까?"
				  ;
            rtn = await $c.win.confirm(v_msg);
			if (!rtn) {
				ds_obj.undoRow(i);
				return;
			}
		}

		if (ds_obj.getCellData(i, "bulkVehclBpYn") == "1") {
            rtn = await $c.win.confirm("차량번호 : " + ds_obj.getCellData(i, "vehclNo") + "는  BP등록  차량입니다.<br>계속하시겠습니까?");
			if (!rtn) {		
				ds_obj.undoRow(i);
				return;
			}
		}		

		var toDay = scwin.toDay;		

		var expireDt = ds_obj.getCellData(i, "rglintInspExpireDt");
		expireDt = new Date(Number(expireDt.substr(0,4)),Number(expireDt.substr(4,2)),Number(expireDt.substr(6,2)));
		var remainDtInsp = Math.floor(expireDt.valueOf()/(24*60*60*1000) - toDay.valueOf()/(24*60*60*1000));
		if( remainDtInsp <= 30 && remainDtInsp > -30){
			await $c.win.alert("차량번호"+ds_obj.getCellData(i, "vehclShortCd")
			+"는 <br>정기검사만료일이"+ ds_obj.getCellData(i, "rglintInspExpireDt") +"일 입니다.");
		}

		var expireDtMntn = ds_obj.getCellData(i, "mntnInspExpireDt");
		expireDtMntn = new Date(Number(expireDtMntn.substr(0,4)),Number(expireDtMntn.substr(4,2)),Number(expireDtMntn.substr(6,2)));
		var remainDtMntn = Math.floor(expireDtMntn.valueOf()/(24*60*60*1000) - toDay.valueOf()/(24*60*60*1000));
		if( remainDtMntn <= 30 && remainDtMntn > -30){
			await $c.win.alert("차량번호"+ds_obj.getCellData(i, "vehclShortCd")
			+"는 <br>정밀검사만료일이"+ ds_obj.getCellData(i, "mntnInspExpireDt") +"일 입니다.");
		}

		var expireDtChk = ds_obj.getCellData(i, "rglintChkExpireDt");
		expireDtChk = new Date(Number(expireDtChk.substr(0,4)),Number(expireDtChk.substr(4,2)),Number(expireDtChk.substr(6,2)));
		var remainDtChk = Math.floor(expireDtChk.valueOf()/(24*60*60*1000) - toDay.valueOf()/(24*60*60*1000));
		if( remainDtChk <= 30 && remainDtChk > -30){
			await $c.win.alert("차량번호"+ds_obj.getCellData(i, "vehclShortCd")
			+"는 <br>정기정검만료일이"+ ds_obj.getCellData(i, "rglintChkExpireDt") +"일 입니다.");
		}				

		var v_ret = new Array();
        v_ret[0 ] = ds_obj.getCellData(i, "vehclNo")      ;
        v_ret[1 ] = ds_obj.getCellData(i, "eqCd")         ;
        v_ret[2 ] = ds_obj.getCellData(i, "eqKndCd")      ;
        v_ret[3 ] = ds_obj.getCellData(i, "vehclKnd")     ;
        v_ret[4 ] = ds_obj.getCellData(i, "eqNrmCd")      ;
        v_ret[5 ] = ds_obj.getCellData(i, "vehclNrm")     ;
        v_ret[6 ] = ds_obj.getCellData(i, "clntNo")       ;
        v_ret[7 ] = ds_obj.getCellData(i, "clntNm")       ;
        v_ret[8 ] = ds_obj.getCellData(i, "vehclShortCd") ;
        v_ret[9 ] = ds_obj.getCellData(i, "drvEmpNo")     ;
        v_ret[10] = ds_obj.getCellData(i, "drvNm")        ;
        v_ret[11] = ds_obj.getCellData(i, "mpNo")         ;
        v_ret[12] = ds_obj.getCellData(i, "trsNo")        ;
        v_ret[13] = ds_obj.getCellData(i, "logisLnkEqCd") ;
        v_ret[14] = ds_obj.getCellData(i, "chassisNo")    ;
        v_ret[15] = ds_obj.getCellData(i, "lnkEqKndCd")   ;
        v_ret[16] = ds_obj.getCellData(i, "chassisKnd")   ;
        v_ret[17] = ds_obj.getCellData(i, "lnkEqNrmCd")   ;
        v_ret[18] = ds_obj.getCellData(i, "chassisNrm")   ;
        v_ret[19] = ds_obj.getCellData(i, "assgnLobranCd");

        v_ret[20] = ds_obj.getCellData(i, "posnClsCd")    ;

        v_ret[21] = ds_obj.getCellData(i, "mobileIndictYn");
        v_ret[22] = ds_obj.getCellData(i, "vehclIdCardNo");
        v_ret[23] = ds_obj.getCellData(i, "chassisShortCd");
        v_ret[24] = ds_obj.getCellData(i, "mbssysVehclYn");
        v_ret[25] = ds_obj.getCellData(i, "arvDt");
        v_ret[26] = ds_obj.getCellData(i, "dptWrkPlCd");
        v_ret[27] = ds_obj.getCellData(i, "chassisSiz");
        v_ret[28] = ds_obj.getCellData(i, "chassisTyp");

        // BP차량유무 
        v_ret[29] = ds_obj.getCellData(i, "bulkVehclBpYn");

		scwin.arrRtnVal[cnt++] = v_ret;
	}
	//window.returnValue = scwin.arrRtnVal;
	//window.close();

    $c.win.closePopup(scwin.arrRtnVal);
};



//-------------------------------------------------------------------------
// Windows Close
//-------------------------------------------------------------------------
scwin.f_WinClose = function() {
    scwin.arrRtnVal = new Array();
    scwin.arrRtnVal[0] = "N/A";
    $c.win.closePopup(scwin.arrRtnVal);
};


//-------------------------------------------------------------------------
// function name : f_vehclKnd
// function desc : 차량종류 검색
//-------------------------------------------------------------------------
scwin.f_vehclKnd = async function() {
    dma_vehclKnd.set("sysCd", "EquipmentNonUsableEBC");
    dma_vehclKnd.set("queryId", "retriveKindCodeListCombo");

    ds_vehclKnd.removeAll();

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_vehclKnd);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_vehclKnd_submitdone();
    } else {
        scwin.comboRtnFlag02 = false;
    }
};

scwin.sbm_vehclKnd_submitdone = async function (e) {
    //for=ds_vehclKnd event=OnLoadCompleted
    ds_vehclKnd.insertRow(0);
    ds_vehclKnd.setCellData(0, "name", "전체");
    ds_vehclKnd.setCellData(0,"code", "");

    lc_vehclKnd.setSelectedIndex(0);

    scwin.comboRtnFlag02 = true;
};



//-------------------------------------------------------------------------
// function name : f_vehclNrm
// function desc : 차량종류 규격 콤보 조회
//-------------------------------------------------------------------------
scwin.f_vehclNrm = async function(param1) {
    dma_vehclNrm.set("sysCd", "EquipmentNonUsableEBC");
    dma_vehclNrm.set("queryId", "retrivecComboNrmCodeList");
    dma_vehclNrm.set("param1", param1);

    ds_vehclNrm.removeAll();

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_vehclNrm);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_vehclNrm_submitdone();
    }
};

scwin.sbm_vehclNrm_submitdone = async function (e) {
    //for=ds_vehclNrm event=OnLoadCompleted
    ds_vehclNrm.insertRow(0);
    ds_vehclNrm.setCellData(0,"name", "전체");
    ds_vehclNrm.setCellData(0,"code", "");

    lc_vehclNrm.setSelectedIndex(0);
};



//-------------------------------------------------------------------------
// function name : f_cargoCls
// function desc : 운송화물 구분 검색
//-------------------------------------------------------------------------
scwin.f_cargoCls = async function() {
    dma_cargoCls.set("sysCd", "EquipmentNonUsableEBC");
    dma_cargoCls.set("queryId", "retriveCargoCodeListCombo");

    ds_cargoCls.removeAll();

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_cargoCls);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_cargoCls_submitdone();
    } else {
        scwin.comboRtnFlag03 = false;
    }
};

scwin.sbm_cargoCls_submitdone = async function (e) {
    //for=ds_cargoCls event=OnLoadCompleted
    ds_cargoCls.insertRow(0);
    ds_cargoCls.setCellData(0,"name", "전체");
    ds_cargoCls.setCellData(0,"code", "");
    lc_cargoClsCd.setValue(scwin.arrParent[0][3]);

    if (scwin.gv_strAllSearchTF == "F") {
	    lc_cargoClsCd.setValue("");
    }

    var gubun = scwin.arrParent[0][3];
    if (scwin.gv_strAllSearchTF == "F") {
	    gubun = "";
    }
    await scwin.f_RetrieveSecondCoCls(gubun);
    scwin.f_changGridColumnName(lc_cargoClsCd.getValue());

    if ( gubun == DsConstants.CARGO_CLS_CD_BULK ) {
        await scwin.f_RetrieveDistrict(DsConstants.WRK_DISTRICT_CD_BWK);
    } else if ( gubun == DsConstants.CARGO_CLS_CD_CONTAINER ) {
        await scwin.f_RetrieveDistrict(DsConstants.WRK_DISTRICT_CD_CMPST);
    } else {
    	await scwin.f_RetrieveDistrict();
    }

    //to-do 무슨기능인지 모르겠음.
    //cfStyleGrid(gr_retrieveUsableVehiclesPresent,"comn");

    scwin.comboRtnFlag03 = true;
};


