scwin.f_changGridColumnName = function(val) {
    var change = lc_cargoClsCd.getSelectedIndex();
    if ( change == 1){
        scwin.showGridNm = "gr_retrieveUsableVehiclesPresent2";
        gr_retrieveUsableVehiclesPresent1.hide();
        gr_retrieveUsableVehiclesPresent2.show("");

        gr_retrieveUsableVehiclesPresent2.setHeaderValue("column9", "대표화종1");
        gr_retrieveUsableVehiclesPresent2.setHeaderValue("column3", "대표화종2");
    } else if( change == 0 || change == 2){
        scwin.showGridNm = "gr_retrieveUsableVehiclesPresent2";
        gr_retrieveUsableVehiclesPresent1.hide();
        gr_retrieveUsableVehiclesPresent2.show("");

        gr_retrieveUsableVehiclesPresent2.setHeaderValue("column9", "샤시종류");
        gr_retrieveUsableVehiclesPresent2.setHeaderValue("column3", "샤시규격");
    } else {
        scwin.showGridNm = "gr_retrieveUsableVehiclesPresent1";
        gr_retrieveUsableVehiclesPresent1.show("");
        gr_retrieveUsableVehiclesPresent2.hide();
    }
};



//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function(callObj,disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList;  // 공통POP-UP -> 요청화면 

    switch (disGubun)
    {
        case 1:

            //초기화 처리.
            em_clntNo.setValue("");
            txt_clntNm.setValue("");

            scwin.udc_objNm = callObj.org_id;

            callObj.setSelectId("retrieveCarKindClntInfo");

            // 협력업체(차량매입)
            await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc	// XML상의 SELECT ID	
                                    ,pCode					// 화면에서의 ??? Code Element의	Value
                                    ,pName					// 화면에서의 ??? Name Element의	Value
                                    ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					// Title순서	
                                    ,null					// 보여주는 각 컬럼들의 폭	
                                    ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                    ,DsConstants.PCHS_CLNT_CLS_CD_HIRECAR					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                    ,null					// 윈도우 위치 Y좌표	
                                    ,null					// 윈도우 위치 X좌표
                                    ,null					// 중복체크여부	("F")
                                    ,pAllSearch					// 전체검색허용여부	("F")
                                    ,"협력업체,협력업체코드,협력업체명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    );
            break;
    }
};

scwin.udc_AllInOne_callBackFunc = function (rtnList) {
    let codeObj;
    let nameObj;

    if(scwin.udc_objNm == "udc_clnt") {
        codeObj = em_clntNo;
        nameObj = txt_clntNm;
    }

    $c.gus.cfSetReturnValue(rtnList, codeObj, nameObj);
};


//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function(callObj, inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        await scwin.f_openCommonPopUp(callObj, disGubun, pVal, '', 'T', 'T');
    }
    // inObj가 코드명 필드일 경우 팝업
    else {
        await scwin.f_openCommonPopUp(callObj, disGubun, '', pVal, 'T', 'T');
    }
};


