//for=ds_results event=OnLoadCompleted
//조회버튼 클릭하여 dataList 수신받으면 아래 하기로직 수행되어야함.
scwin.retrieveEnd = async function () {
    grid_total.show("");
    totalRows.setValue(ds_results.getRowCount());
    if ( ds_results.getRowCount() == 0 ) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    } else {

        ds_results2.removeAll();
        ds_results2.setJSON(ds_results.getAllJSON());
        ds_results2.reform();


        if(scwin.showGridNm == "gr_retrieveUsableVehiclesPresent1") {
            if (ds_results.getRowCount() == 1 && scwin.gv_strExistTF == 'T')	{
                ds_results.setCellData(0, "chk", "1");
                await scwin.f_rtnValue();   

                gr_retrieveUsableVehiclesPresent1.setFocusedCell(0, 0);
            }
        } else if(scwin.showGridNm == "gr_retrieveUsableVehiclesPresent2") {
            if (ds_results2.getRowCount() == 1 && scwin.gv_strExistTF == 'T')	{
                ds_results2.setCellData(0, "chk", "1");
                await scwin.f_rtnValue();   

                gr_retrieveUsableVehiclesPresent2.setFocusedCell(0, 0);
            }
        }
    }
};
